effect.script:
function animate(env,el,p) {
    let t = env.time;
    var a = (90. - p.angle) * (Math.PI / 180);
    var dx = Math.sin(a);
    var dy = Math.cos(a);
    let m;
    if( p.type == 0 ) {
        m = Math.sin((p.freq * 2.0 + p.phase*2.0) * 3.14159)
    } else {
        m = AM.triangle((p.freq * 2.0 + p.phase*2.0) / 2.0 + p.phase)
    }
    if( p.direction == 1 ) {
        el.transform.location.z += p.mag * m;
    } else if( p.direction == 2 ) {
        dx *= p.mag * m;
        dy *= p.mag * m;
        el.transform.location.x += dx;
        el.transform.location.y += dy;
        let m2;
        if( p.type == 0 ) {
            m2 = Math.sin((p.freq * 2.0 + (p.phase+0.25)*2.0) * 3.14159)
        } else {
            m2 = AM.triangle((p.freq * 2.0 + (p.phase+0.125)*2.0) / 2.0 + p.phase+0.125)
        }
        el.transform.location.z += p.mag * m2;
    } else {
        dx *= p.mag * m;
        dy *= p.mag * m;
        el.transform.location.x += dx;
        el.transform.location.y += dy;
    }
    return el;
}
